const src = $('Extrair e Preparar').first().json;
const rawObj = items[0].json || {};
const rawText = String(rawObj.text ?? rawObj.response ?? rawObj.output ?? '');

const EVENTOS = [
  'busca_produto',
  'produto_nao_encontrado',
  'orcamento_gerado',
  'orcamento_aceito',
  'pediu_mais_barato',
  'upsell_oferecido',
  'upsell_aceito',
  'upsell_recusado',
  'pediu_vendedor',
  'fora_escopo'
];
const SENTIMENTOS = ['positivo', 'neutro', 'negativo'];

function parseModelJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json/gi, '').replace(/```/g, '').trim();
  try { return JSON.parse(clean); } catch (_) {}

  const first = clean.indexOf('{');
  const last = clean.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try { return JSON.parse(clean.slice(first, last + 1)); } catch (_) {}
  }

  return null;
}

function toNumber(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  const n = parseFloat(String(v).replace(/[^\\d,.-]/g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function normalizeProdutos(v) {
  const arr = Array.isArray(v) ? v : (v && typeof v === 'object' ? [v] : []);
  return arr
    .map((p) => {
      const nome = String(p?.nome ?? '').trim();
      const marca = String(p?.marca ?? '').trim();
      const preco = String(p?.preco ?? '').trim();
      const volume = String(p?.volume ?? '').trim();
      if (!nome && !marca && !preco && !volume) return null;
      return { nome, marca, preco, volume };
    })
    .filter(Boolean);
}

function inferEvento(parsed, user, bot) {
  const evt = String(parsed?.evento ?? '').trim().toLowerCase();
  if (EVENTOS.includes(evt)) return evt;

  if (/fecha|quero esse|pode separar|vou levar|esse mesmo|pode fechar/i.test(user)) return 'orcamento_aceito';
  if (/mais barato|mais em conta|desconto/i.test(user)) return 'pediu_mais_barato';
  if (/vou chamar|vendedor|atendente|consultor/i.test(bot)) return 'pediu_vendedor';
  if (/nao encontr|n\u00e3o encontr|nao temos|n\u00e3o temos|indisponivel|indispon\u00edvel/i.test(bot)) return 'produto_nao_encontrado';

  if (/kit|combo|rolo.*bandeja|bandeja.*fita|tambem recomendo|tamb\u00e9m recomendo/i.test(bot)) {
    if (/(aceito|pode incluir|inclui|quero tambem|quero tamb\u00e9m|pode ser)/i.test(user)) return 'upsell_aceito';
    if (/(nao|n\u00e3o|sem|dispenso|deixa)/i.test(user)) return 'upsell_recusado';
    return 'upsell_oferecido';
  }

  if (/total|orcamento|or\u00e7amento|subtotal|itens?/i.test(bot) && /R\\$/i.test(bot)) return 'orcamento_gerado';
  if (/R\\$/i.test(bot)) return 'busca_produto';

  return 'fora_escopo';
}

const parsed = parseModelJson(rawText) || {};
const user = String(src.user_message || '');
const bot = String(src.bot_message || '');

const evento = inferEvento(parsed, user, bot);
const produtos = normalizeProdutos(parsed.produtos);
const valor_total = toNumber(parsed.valor_total);
let sentimento = String(parsed.sentimento ?? 'neutro').trim().toLowerCase();
if (!SENTIMENTOS.includes(sentimento)) sentimento = 'neutro';

let detalhes = String(parsed.detalhes ?? '').trim();
if (!detalhes) detalhes = 'classificacao_auto:' + evento;
if (detalhes.length > 500) detalhes = detalhes.slice(0, 500);

return [{
  json: {
    ...src,
    evento,
    produtos,
    valor_total,
    sentimento,
    detalhes,
    classificacao_parse_ok: Object.keys(parsed).length > 0,
    classificacao_raw: rawText.slice(0, 4000),
  }
}];

